examples:
// Informações de um livro da biblioteca
let titulo: string = "Dom Casmurro";
let autor: string = "Machado de Assis";

console.log(titulo);        // Dom Casmurro
console.log(titulo.length); // 12
console.log(autor.toUpperCase()); // MACHADO DE ASSIS

// Buscando uma palavra dentro de um texto
let bio: string = "Estudante de programação e música";

console.log(bio.includes("música"));       // true
console.log(bio.includes("esporte"));      // false
console.log(bio.includes("programação")); // true

// Acessando letras pela posição (começa no 0!)
let cidade: string = "Curitiba";

console.log(cidade[0]); // C
console.log(cidade[1]); // u
console.log(cidade[7]); // a
console.log(cidade.length); // 8

// Transformando maiúsculas e minúsculas
let grito: string = "para de gritar!";
let sussurro: string = "EU FALO BAIXO";

console.log(grito.toUpperCase());    // PARA DE GRITAR!
console.log(sussurro.toLowerCase()); // eu falo baixo

// Strings com espaços também contam
let frase: string = "Eu gosto de pizza";

console.log(frase.length);       // 17
console.log(frase[2]);           // " " (é o espaço!)
console.log(frase.includes("pizza")); // true

// Números entre aspas são strings, não numbers!
let cep: string = "80040-020";
let telefone: string = "(41) 99999-0000";

console.log(typeof cep);       // string
console.log(typeof telefone);  // string
console.log(cep.length);       // 9

// Calculando média de notas na escola
let nota1: number = 8;
let nota2: number = 6.5;
let nota3: number = 9;

let media: number = (nota1 + nota2 + nota3) / 3;
console.log(media); // 7.833333333333333
console.log(Math.round(media)); // 8

// Conta de restaurante dividida entre amigos
let conta: number = 87.50;
let pessoas: number = 4;

let porPessoa: number = conta / pessoas;
console.log(porPessoa); // 21.875
console.log(Math.ceil(porPessoa)); // 22 (arredonda pra cima!)

// Descobrindo se um número é par ou ímpar
let numero: number = 15;

console.log(numero % 2); // 1 (ímpar: sobra 1)
console.log(8 % 2);      // 0 (par: divide certinho)
console.log(21 % 2);     // 1 (ímpar)

// Convertendo minutos para horas e minutos
let totalMinutos: number = 145;

let horas: number = Math.floor(totalMinutos / 60);
let minutosRestantes: number = totalMinutos % 60;

console.log(horas);             // 2
console.log(minutosRestantes);  // 25

// Potência e raiz quadrada
let lado: number = 5;
let area: number = lado ** 2;
console.log(area); // 25

let diagonal: number = Math.sqrt(2 * (lado ** 2));
console.log(Math.round(diagonal)); // 7

// Desconto de uma compra
let precoOriginal: number = 120;
let desconto: number = 15;

let valorDesconto: number = precoOriginal * (desconto / 100);
let precoFinal: number = precoOriginal - valorDesconto;

console.log(valorDesconto); // 18
console.log(precoFinal);    // 102

// Configurações de um app
let modoEscuro: boolean = true;
let notificacoesAtivas: boolean = false;
let somLigado: boolean = true;

console.log(modoEscuro);         // true
console.log(notificacoesAtivas); // false
console.log(somLigado);          // true

// Comparações geram booleans automaticamente
let temperatura: number = 35;

let estaQuente: boolean = temperatura > 30;
let estaCongelando: boolean = temperatura < 0;

console.log(estaQuente);     // true
console.log(estaCongelando); // false

// Verificando se um aluno passou
let nota: number = 6.5;
let frequencia: number = 80;

let notaSuficiente: boolean = nota >= 7;
let frequenciaSuficiente: boolean = frequencia >= 75;

console.log(notaSuficiente);      // false
console.log(frequenciaSuficiente); // true

// Cuidado: true vs "true" são DIFERENTES!
let ligado: boolean = true;
let textoLigado: string = "true";

console.log(typeof ligado);      // boolean
console.log(typeof textoLigado); // string
// São tipos completamente diferentes!

// Comparando igualdade com ===
let idade: number = 18;

console.log(idade === 18); // true
console.log(idade === 17); // false
console.log(idade !== 10); // true (diferente de 10? sim!)

// Checklist antes de uma viagem
let passaporteOk: boolean = true;
let malaFeita: boolean = true;
let alarmeConfigurado: boolean = false;

console.log(passaporteOk);       // true
console.log(malaFeita);          // true
console.log(alarmeConfigurado);  // false

// Mensagem personalizada para um aluno
let nome: string = "Beatriz";
let nota: number = 9.5;

console.log(`Parabéns, ${nome}! Sua nota foi ${nota}.`); 
// Parabéns, Beatriz! Sua nota foi 9.5.

// Fazendo contas dentro do template literal
let preco: number = 45;
let quantidade: number = 3;

console.log(`Total: R$ ${preco * quantidade}`);
// Total: R$ 135

console.log(`Preço unitário: R$ ${preco}`);
// Preço unitário: R$ 45

// Comparação: concatenação vs template literal
let cidade: string = "Gramado";
let graus: number = 5;

// Jeito antigo (confuso):
console.log("Agora em " + cidade + ": " + graus + "°C");

// Template literal (limpo):
console.log(`Agora em ${cidade}: ${graus}°C`);

// Preenchendo dados de um perfil
let usuario: string = "@maria_dev";
let seguidores: number = 1200;
let posts: number = 47;

console.log(`${usuario} | ${seguidores} seguidores | ${posts} posts`);
// @maria_dev | 1200 seguidores | 47 posts

// Expressões mais complexas dentro de ${ }
let acertos: number = 7;
let total: number = 10;

console.log(`Resultado: ${acertos}/${total} (${(acertos / total) * 100}%)`);
// Resultado: 7/10 (70%)

// Ternário dentro de template literal
let temperatura: number = 38;

console.log(`Temperatura: ${temperatura}°C — ${temperatura > 30 ? "Muito quente!" : "Agradável"}`);
// Temperatura: 38°C — Muito quente!

// Padrão: declarar variáveis e formatar com template literal
const fruta: string = "Maçã";
const peso: number = 150;
const organica: boolean = true;

console.log(`${fruta} | Peso: ${peso}g | Orgânica: ${organica}`);
// Maçã | Peso: 150g | Orgânica: true

// Dados de um aluno em uma ficha escolar
const nomeAluno: string = "Lucas";
const turma: string = "7B";
const media: number = 8;
const aprovado: boolean = true;

console.log(`${nomeAluno} — ${turma} | Média: ${media} | Aprovado: ${aprovado}`);
// Lucas — 7B | Média: 8 | Aprovado: true

// const é melhor que let quando o valor não muda
const NOME: string = "Aria";
const NIVEL: number = 5;

// NOME = "Outro"; // ERRO: const não permite reatribuir
console.log(`${NOME} está no nível ${NIVEL}`);
// Aria está no nível 5

// Boolean no template literal vira texto automaticamente
const temDesconto: boolean = false;
const precoFinal: number = 99;

console.log(`Preço: R$ ${precoFinal} | Desconto: ${temDesconto}`);
// Preço: R$ 99 | Desconto: false

// Cuidado com o travessão (—) vs hífen (-)
console.log("Com travessão: Kael — Guerreiro");
console.log("Com hífen: Kael - Guerreiro");
// São caracteres diferentes! O exercício pede travessão.

// Montando uma string formatada com 5 variáveis
const marca: string = "Nike";
const modelo: string = "Air Max";
const tamanho: number = 38;
const preco: number = 599;
const disponivel: boolean = true;

console.log(`${marca} ${modelo} | Tam: ${tamanho} | R$ ${preco} | Disponível: ${disponivel}`);
// Nike Air Max | Tam: 38 | R$ 599 | Disponível: true

// Mostrando operações com notas
const nota1: number = 8;
const nota2: number = 6;

console.log(`${nota1} + ${nota2} = ${nota1 + nota2}`);
// 8 + 6 = 14

console.log(`Média: ${(nota1 + nota2) / 2}`);
// Média: 7

// Cálculos dentro de template literals
const preco: number = 50;
const desconto: number = 15;

console.log(`${preco} - ${desconto} = ${preco - desconto}`);
// 50 - 15 = 35

// Divisão pode gerar decimais
const total: number = 100;
const pessoas: number = 3;

console.log(`${total} / ${pessoas} = ${total / pessoas}`);
// 100 / 3 = 33.333333333333336

// As quatro operações de uma vez
const x: number = 10;
const y: number = 4;

console.log(`${x} + ${y} = ${x + y}`);  // 10 + 4 = 14
console.log(`${x} - ${y} = ${x - y}`);  // 10 - 4 = 6
console.log(`${x} * ${y} = ${x * y}`);  // 10 * 4 = 40
console.log(`${x} / ${y} = ${x / y}`);  // 10 / 4 = 2.5

// Erro comum: esquecer de usar template literal
const a: number = 5;
const b: number = 3;

// ERRADO — mostra só o resultado:
console.log(a + b); // 8

// CERTO — mostra a conta completa:
console.log(`${a} + ${b} = ${a + b}`); // 5 + 3 = 8

// O + fora das chaves é texto, dentro é operação
const m: number = 7;
const n: number = 2;

// O primeiro + é o SÍMBOLO que aparece na string
// O segundo + é a OPERAÇÃO matemática
console.log(`${m} + ${n} = ${m + n}`);
// 7 + 2 = 9

// Revisão: os três tipos básicos
let titulo: string = "Interestelar";
let duracao: number = 169;
let assistido: boolean = false;

console.log(typeof titulo);   // string
console.log(typeof duracao);  // number
console.log(typeof assistido); // boolean

// Revisão: concatenação de strings com +
let primeira: string = "Bom";
let segunda: string = " ";
let terceira: string = "dia!";

console.log(primeira + segunda + terceira); // Bom dia!

// Revisão: 42 vs "42" — tipos diferentes!
let numero: number = 42;
let texto: string = "42";

console.log(numero + 8);  // 50 (soma numérica)
console.log(texto + "8"); // 428 (concatenação de texto!)

// Revisão: template literal com expressão
let idade: number = 12;
console.log(`Daqui a 6 anos: ${idade + 6}`); // Daqui a 6 anos: 18
console.log(`Dobro da idade: ${idade * 2}`); // Dobro da idade: 24

// Revisão: comparações geram booleans
let nota: number = 7;

console.log(nota >= 7);  // true
console.log(nota === 10); // false
console.log(nota < 5);   // false
